"use client";
import { motion } from "framer-motion";
import { FaGithub, FaLinkedin, FaInstagram, FaXTwitter, FaWhatsapp } from "react-icons/fa6";
import { useUserProfile } from "../hooks/useUserProfile";
import type { Transition } from "framer-motion";
import Image from "next/image";

const fadeUp = (delay = 0) => ({
  initial: { opacity: 0, y: 20 },
  animate: { opacity: 1, y: 0 },
  transition: { duration: 0.6, ease: "easeOut", delay } as Transition,
});

const fadeIn = (delay = 0) => ({
  initial: { opacity: 0, scale: 0.95 },
  animate: { opacity: 1, scale: 1 },
  transition: { duration: 0.7, ease: "easeOut", delay } as Transition,
});

// Replace this with the actual base64 data from AirBrush_20260218190359.jpg
// In production, use a proper image URL or import instead of base64 inline
const HERO_PHOTO_B64 = "";

export function Hero() {
  const { user, loading } = useUserProfile();

  const scheduleHref = user?.whatsapp
    ? `https://wa.me/${user.whatsapp}`
    : user?.socials?.gmail
      ? `mailto:${user.socials.gmail}`
      : "#contact";

  const socials = [
    { href: user?.socials?.github, icon: FaGithub, label: "GitHub" },
    { href: user?.socials?.linkedin, icon: FaLinkedin, label: "LinkedIn" },
    { href: user?.socials?.twitter, icon: FaXTwitter, label: "Twitter" },
    { href: user?.socials?.instagram, icon: FaInstagram, label: "Instagram" },
  ].filter((s) => !!s.href);

  if (loading) {
    return (
      <section className="min-h-[85vh] flex items-center px-6">
        <div className="w-full max-w-5xl mx-auto animate-pulse space-y-6">
          <div className="h-20 w-3/4 bg-white/5 rounded" />
          <div className="h-4 w-96 bg-white/5 rounded" />
        </div>
      </section>
    );
  }

  return (
    <section id="hero" className="min-h-[85vh] flex items-center px-6 lg:px-8 overflow-hidden">
      <div className="w-full max-w-6xl mx-auto py-20 lg:py-28 flex flex-col lg:flex-row items-center gap-12 lg:gap-0">

        {/* ── LEFT: Text Content ── */}
        <div className="flex-1 lg:pr-8">

          {/* Big name */}
          <motion.div {...fadeUp(0)}>
            <h1
              className="font-black tracking-[-0.04em] leading-[0.9] uppercase"
              style={{ fontSize: "clamp(56px, 10vw, 120px)" }}
            >
              <span className="text-white block">WASEEM</span>
              <span className="text-[#555] block">AKRAM</span>
            </h1>
          </motion.div>

          {/* Headline from backend */}
          <motion.div {...fadeUp(0.1)} className="flex items-center gap-4 mt-8 mb-5">
            <div className="h-px w-8 bg-white/20 shrink-0" />
            <p className="text-[13px] font-light tracking-[0.06em] text-[#bbb]">
              {user?.headline ?? "Software Engineer | Full-Stack Developer"}
            </p>
          </motion.div>

          {/* Description from backend */}
          <motion.p
            {...fadeUp(0.18)}
            className="text-[15px] font-light text-[#888] leading-[1.8] max-w-lg mb-10"
            style={{ letterSpacing: "0.01em" }}
          >
            {user?.description ??
              "Full-Stack Developer from Pakistan — I build fast, scalable web apps from idea to deployment."}
          </motion.p>

          {/* CTAs */}
          <motion.div {...fadeUp(0.24)} className="flex flex-wrap items-center gap-6">
            <a
              href={scheduleHref}
              target={user?.whatsapp ? "_blank" : undefined}
              rel="noopener noreferrer"
              className="text-[11px] tracking-[0.12em] uppercase font-semibold px-7 py-3 bg-white text-[#0d0d0d] hover:bg-white/90 transition-all duration-200 rounded-sm flex items-center gap-2"
            >
              <FaWhatsapp className="w-4 h-4 shrink-0" />
              Get in touch
            </a>
            {user?.cvUrl && (
              <a
                href={user.cvUrl}
                target="_blank"
                rel="noopener noreferrer"
                className="text-[11px] tracking-[0.12em] uppercase text-[#888] border border-[#2a2a2a] px-7 py-3 hover:border-white/20 hover:text-[#bbb] transition-all duration-200 rounded-sm flex items-center gap-2"
              >
                Download CV
                <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                  <path d="M5 12h14M12 5l7 7-7 7" />
                </svg>
              </a>
            )}
          </motion.div>
        </div>

        {/* ── RIGHT: Professional Photo ── */}
        <motion.div
          {...fadeIn(0.3)}
          className="relative flex-shrink-0 w-72 lg:w-80 xl:w-96"
        >
          {/* Decorative background glow */}
          <div
            className="absolute inset-0 rounded-2xl"
            style={{
              background: "radial-gradient(ellipse at 50% 80%, rgba(255,255,255,0.04) 0%, transparent 70%)",
              transform: "scale(1.1)",
            }}
          />

          {/* Corner accent lines */}
          <div className="absolute top-0 left-0 w-8 h-8 border-t border-l border-white/20 rounded-tl-2xl z-10" />
          <div className="absolute top-0 right-0 w-8 h-8 border-t border-r border-white/20 rounded-tr-2xl z-10" />
          <div className="absolute bottom-0 left-0 w-8 h-8 border-b border-l border-white/20 rounded-bl-2xl z-10" />
          <div className="absolute bottom-0 right-0 w-8 h-8 border-b border-r border-white/20 rounded-br-2xl z-10" />

          {/* Photo */}
          <div className="relative rounded-2xl overflow-hidden" style={{ aspectRatio: "3/4" }}>
            <Image
              src={`data:image/jpeg;base64,${HERO_PHOTO_B64}`}
              alt="Waseem Akram"
              className="w-full h-full object-cover object-top"
              style={{
                filter: "grayscale(0%) contrast(1.05) brightness(1.02)",
              }}
              width={300}
              height={400}
            />
            {/* Subtle dark vignette at bottom */}
            <div
              className="absolute bottom-0 left-0 right-0 h-24"
              style={{
                background: "linear-gradient(to top, rgba(13,13,13,0.5) 0%, transparent 100%)",
              }}
            />
          </div>

          {/* Floating badge — stats */}
          <motion.div
            initial={{ opacity: 0, x: 20 }}
            animate={{ opacity: 1, x: 0 }}
            transition={{ duration: 0.6, delay: 0.5 }}
            className="absolute -right-4 top-8 bg-[#111] border border-[#222] rounded-lg px-4 py-3 backdrop-blur-sm"
          >
            <p className="text-white font-bold text-xl leading-none">2+</p>
            <p className="text-[#666] text-[10px] tracking-wider uppercase mt-1">Years Exp</p>
          </motion.div>

          <motion.div
            initial={{ opacity: 0, x: -20 }}
            animate={{ opacity: 1, x: 0 }}
            transition={{ duration: 0.6, delay: 0.6 }}
            className="absolute -left-4 bottom-12 bg-[#111] border border-[#222] rounded-lg px-4 py-3 backdrop-blur-sm"
          >
            <p className="text-white font-bold text-xl leading-none">10+</p>
            <p className="text-[#666] text-[10px] tracking-wider uppercase mt-1">Projects</p>
          </motion.div>
        </motion.div>
      </div>

      {/* Vertical socials — fixed left side */}
      {socials.length > 0 && (
        <div className="hidden lg:flex fixed left-8 top-1/2 -translate-y-1/2 z-30 flex-col items-center gap-6">
          {socials.map(({ href, icon: Icon, label }) => (
            <a
              key={label}
              href={href!}
              target="_blank"
              rel="noopener noreferrer"
              title={label}
              className="text-[#777] hover:text-white transition-colors duration-200"
            >
              <Icon className="w-[20px] h-[20px]" />
            </a>
          ))}
          <div className="w-px h-16 bg-white/10 mt-2" />
        </div>
      )}
    </section>
  );
}